-- Stage SQL: CCMS_CTR_ACTV_RSN (Incremental)
-- Location: s3://c108-dev-fpacfsa-final-zone/cnsv/_configs/stg/CCMS_CTR_ACTV_RSN/incremental/CCMS_CTR_ACTV_RSN.sql
-- =============================================================================SELECT * FROM(SELECT DISTINCT ADM_CNTY_FSA_CD,ADM_ST_FSA_CD,CRE_DT,CRE_USER_NM,CTR_ACTV_RSN_ID,CTR_ACTV_RSN_TYPE_CD,CTR_ACTV_RSN_TYPE_DESC,CTR_ACTV_TYPE_CD,CTR_DET_ID,CTR_NBR,CTR_SFX_NBR,DATA_STAT_CD,LAST_CHG_DT,LAST_CHG_USER_NM,SGNP_NBR,SGNP_STYPE_AGR_NM,SGNP_SUB_CAT_NM,SGNP_TYPE_NM,CDC_OPER_CD,op AS CDC_OPER_CD,,ROW_NUMBER() over ( partition by CRE_DT,CTR_ACTV_RSN_IDorder by TBL_PRIORITY ASC, LAST_CHG_DT DESC ) AS row_num_partFROM(SELECT MASTER_CONTRACT.ADMINISTRATIVE_COUNTY_FSA_CODE ADM_CNTY_FSA_CD,MASTER_CONTRACT.ADMINISTRATIVE_STATE_FSA_CODE ADM_ST_FSA_CD,CONTRACT_ACTIVITY_REASON.CREATION_DATE CRE_DT,CONTRACT_ACTIVITY_REASON.CREATION_USER_NAME CRE_USER_NM,CONTRACT_ACTIVITY_REASON.CONTRACT_ACTIVITY_REASON_IDENTIFIER CTR_ACTV_RSN_ID,CONTRACT_ACTIVITY_REASON.CONTRACT_ACTIVITY_REASON_TYPE_CODE CTR_ACTV_RSN_TYPE_CD,CONTRACT_ACTIVITY_REASON_TYPE.CONTRACT_ACTIVITY_REASON_TYPE_DESCRIPTION CTR_ACTV_RSN_TYPE_DESC,CONTRACT_ACTIVITY_REASON_TYPE.CONTRACT_ACTIVITY_TYPE_CODE CTR_ACTV_TYPE_CD,CONTRACT_ACTIVITY_REASON.CONTRACT_DETAIL_IDENTIFIER CTR_DET_ID,MASTER_CONTRACT.CONTRACT_NUMBER CTR_NBR,CONTRACT_DETAIL.CONTRACT_SUFFIX_NUMBER CTR_SFX_NBR,CONTRACT_ACTIVITY_REASON.DATA_STATUS_CODE DATA_STAT_CD,CONTRACT_ACTIVITY_REASON.LAST_CHANGE_DATE LAST_CHG_DT,CONTRACT_ACTIVITY_REASON.LAST_CHANGE_USER_NAME LAST_CHG_USER_NM,SIGNUP.SIGNUP_NUMBER SGNP_NBR,SIGNUP.SIGNUP_SUBTYPE_AGREEMENT_NAME SGNP_STYPE_AGR_NM,SIGNUP_SUB_CATEGORY.SIGNUP_SUB_CATEGORY_NAME SGNP_SUB_CAT_NM,SIGNUP_TYPE.SIGNUP_TYPE_NAME SGNP_TYPE_NM,--__CDC_OPERATION,CONTRACT_ACTIVITY_REASON.op,1 AS TBL_PRIORITYFrom "fsa-{env}-ccms-cdc".CONTRACT_ACTIVITY_REASONleft join "fsa-{env}-ccms-cdc".CONTRACT_ACTIVITY_REASON_TYPE on CONTRACT_ACTIVITY_REASON.CONTRACT_ACTIVITY_REASON_TYPE_CODE = CONTRACT_ACTIVITY_REASON_TYPE.CONTRACT_ACTIVITY_REASON_TYPE_CODE Left Join "fsa-{env}-ccms-cdc".CONTRACT_DETAIL on CONTRACT_ACTIVITY_REASON.CONTRACT_DETAIL_IDENTIFIER = CONTRACT_DETAIL.CONTRACT_DETAIL_IDENTIFIER  Left Join "fsa-{env}-ccms-cdc".MASTER_CONTRACT On MASTER_CONTRACT.CONTRACT_IDENTIFIER = CONTRACT_DETAIL.CONTRACT_IDENTIFIER Left Join "fsa-{env}-ccms-cdc".SIGNUP on SIGNUP.SIGNUP_IDENTIFIER=MASTER_CONTRACT.SIGNUP_IDENTIFIER Left Join "fsa-{env}-ccms-cdc".SIGNUP_SUB_CATEGORY ON SIGNUP_SUB_CATEGORY.SIGNUP_SUB_CATEGORY_CODE = SIGNUP.SIGNUP_SUB_CATEGORY_CODE Left join "fsa-{env}-ccms-cdc".SIGNUP_TYPE On SIGNUP.SIGNUP_TYPE_CODE = SIGNUP_TYPE.SIGNUP_TYPE_CODE --WHERE __CDC_OPERATION <> 'D'WHERE CONTRACT_ACTIVITY_REASON.op <> 'D'UNIONSELECT MASTER_CONTRACT.ADMINISTRATIVE_COUNTY_FSA_CODE ADM_CNTY_FSA_CD,MASTER_CONTRACT.ADMINISTRATIVE_STATE_FSA_CODE ADM_ST_FSA_CD,CONTRACT_ACTIVITY_REASON.CREATION_DATE CRE_DT,CONTRACT_ACTIVITY_REASON.CREATION_USER_NAME CRE_USER_NM,CONTRACT_ACTIVITY_REASON.CONTRACT_ACTIVITY_REASON_IDENTIFIER CTR_ACTV_RSN_ID,CONTRACT_ACTIVITY_REASON.CONTRACT_ACTIVITY_REASON_TYPE_CODE CTR_ACTV_RSN_TYPE_CD,CONTRACT_ACTIVITY_REASON_TYPE.CONTRACT_ACTIVITY_REASON_TYPE_DESCRIPTION CTR_ACTV_RSN_TYPE_DESC,CONTRACT_ACTIVITY_REASON_TYPE.CONTRACT_ACTIVITY_TYPE_CODE CTR_ACTV_TYPE_CD,CONTRACT_ACTIVITY_REASON.CONTRACT_DETAIL_IDENTIFIER CTR_DET_ID,MASTER_CONTRACT.CONTRACT_NUMBER CTR_NBR,CONTRACT_DETAIL.CONTRACT_SUFFIX_NUMBER CTR_SFX_NBR,CONTRACT_ACTIVITY_REASON.DATA_STATUS_CODE DATA_STAT_CD,CONTRACT_ACTIVITY_REASON.LAST_CHANGE_DATE LAST_CHG_DT,CONTRACT_ACTIVITY_REASON.LAST_CHANGE_USER_NAME LAST_CHG_USER_NM,SIGNUP.SIGNUP_NUMBER SGNP_NBR,SIGNUP.SIGNUP_SUBTYPE_AGREEMENT_NAME SGNP_STYPE_AGR_NM,SIGNUP_SUB_CATEGORY.SIGNUP_SUB_CATEGORY_NAME SGNP_SUB_CAT_NM,SIGNUP_TYPE.SIGNUP_TYPE_NAME SGNP_TYPE_NM,--__CDC_OPERATION,CONTRACT_ACTIVITY_REASON_TYPE.op,2 AS TBL_PRIORITYFrom "fsa-{env}-ccms-cdc".CONTRACT_ACTIVITY_REASON_TYPE   join "fsa-{env}-ccms-cdc".CONTRACT_ACTIVITY_REASON on CONTRACT_ACTIVITY_REASON.CONTRACT_ACTIVITY_REASON_TYPE_CODE = CONTRACT_ACTIVITY_REASON_TYPE.CONTRACT_ACTIVITY_REASON_TYPE_CODELeft Join "fsa-{env}-ccms-cdc".CONTRACT_DETAIL  on CONTRACT_ACTIVITY_REASON.CONTRACT_DETAIL_IDENTIFIER = CONTRACT_DETAIL.CONTRACT_DETAIL_IDENTIFIER Left Join "fsa-{env}-ccms-cdc".MASTER_CONTRACT On MASTER_CONTRACT.CONTRACT_IDENTIFIER = CONTRACT_DETAIL.CONTRACT_IDENTIFIER Left Join "fsa-{env}-ccms-cdc".SIGNUP on SIGNUP.SIGNUP_IDENTIFIER=MASTER_CONTRACT.SIGNUP_IDENTIFIER Left Join "fsa-{env}-ccms-cdc".SIGNUP_SUB_CATEGORY  ON SIGNUP_SUB_CATEGORY.SIGNUP_SUB_CATEGORY_CODE = SIGNUP.SIGNUP_SUB_CATEGORY_CODE Left join "fsa-{env}-ccms-cdc".SIGNUP_TYPE On SIGNUP.SIGNUP_TYPE_CODE = SIGNUP_TYPE.SIGNUP_TYPE_CODE --WHERE __CDC_OPERATION <> 'D'WHERE CONTRACT_ACTIVITY_REASON_TYPE.op <> 'D'
UNIONSELECT MASTER_CONTRACT.ADMINISTRATIVE_COUNTY_FSA_CODE ADM_CNTY_FSA_CD,MASTER_CONTRACT.ADMINISTRATIVE_STATE_FSA_CODE ADM_ST_FSA_CD,CONTRACT_ACTIVITY_REASON.CREATION_DATE CRE_DT,CONTRACT_ACTIVITY_REASON.CREATION_USER_NAME CRE_USER_NM,CONTRACT_ACTIVITY_REASON.CONTRACT_ACTIVITY_REASON_IDENTIFIER CTR_ACTV_RSN_ID,CONTRACT_ACTIVITY_REASON.CONTRACT_ACTIVITY_REASON_TYPE_CODE CTR_ACTV_RSN_TYPE_CD,CONTRACT_ACTIVITY_REASON_TYPE.CONTRACT_ACTIVITY_REASON_TYPE_DESCRIPTION CTR_ACTV_RSN_TYPE_DESC,CONTRACT_ACTIVITY_REASON_TYPE.CONTRACT_ACTIVITY_TYPE_CODE CTR_ACTV_TYPE_CD,CONTRACT_ACTIVITY_REASON.CONTRACT_DETAIL_IDENTIFIER CTR_DET_ID,MASTER_CONTRACT.CONTRACT_NUMBER CTR_NBR,CONTRACT_DETAIL.CONTRACT_SUFFIX_NUMBER CTR_SFX_NBR,CONTRACT_ACTIVITY_REASON.DATA_STATUS_CODE DATA_STAT_CD,CONTRACT_ACTIVITY_REASON.LAST_CHANGE_DATE LAST_CHG_DT,CONTRACT_ACTIVITY_REASON.LAST_CHANGE_USER_NAME LAST_CHG_USER_NM,SIGNUP.SIGNUP_NUMBER SGNP_NBR,SIGNUP.SIGNUP_SUBTYPE_AGREEMENT_NAME SGNP_STYPE_AGR_NM,SIGNUP_SUB_CATEGORY.SIGNUP_SUB_CATEGORY_NAME SGNP_SUB_CAT_NM,SIGNUP_TYPE.SIGNUP_TYPE_NAME SGNP_TYPE_NM,--__CDC_OPERATION,CONTRACT_DETAIL.op,3 AS TBL_PRIORITYFrom "fsa-{env}-ccms-cdc".CONTRACT_DETAIL join "fsa-{env}-ccms-cdc".CONTRACT_ACTIVITY_REASON CONTRACT_ACTIVITY_REASONon CONTRACT_ACTIVITY_REASON.CONTRACT_DETAIL_IDENTIFIER = CONTRACT_DETAIL.CONTRACT_DETAIL_IDENTIFIER  Left Join "fsa-{env}-ccms-cdc".CONTRACT_ACTIVITY_REASON_TYPE  on CONTRACT_ACTIVITY_REASON.CONTRACT_ACTIVITY_REASON_TYPE_CODE = CONTRACT_ACTIVITY_REASON_TYPE.CONTRACT_ACTIVITY_REASON_TYPE_CODE Left Join "fsa-{env}-ccms-cdc".MASTER_CONTRACT  On MASTER_CONTRACT.CONTRACT_IDENTIFIER = CONTRACT_DETAIL.CONTRACT_IDENTIFIER Left Join "fsa-{env}-ccms-cdc".SIGNUP on SIGNUP.SIGNUP_IDENTIFIER=MASTER_CONTRACT.SIGNUP_IDENTIFIER Left Join "fsa-{env}-ccms-cdc".SIGNUP_SUB_CATEGORY  ON SIGNUP_SUB_CATEGORY.SIGNUP_SUB_CATEGORY_CODE = SIGNUP.SIGNUP_SUB_CATEGORY_CODE Left join "fsa-{env}-ccms-cdc".SIGNUP_TYPE  On SIGNUP.SIGNUP_TYPE_CODE = SIGNUP_TYPE.SIGNUP_TYPE_CODE --WHERE __CDC_OPERATION <> 'D'WHERE CONTRACT_DETAIL.op <> 'D'UNIONSELECT MASTER_CONTRACT.ADMINISTRATIVE_COUNTY_FSA_CODE ADM_CNTY_FSA_CD,MASTER_CONTRACT.ADMINISTRATIVE_STATE_FSA_CODE ADM_ST_FSA_CD,CONTRACT_ACTIVITY_REASON.CREATION_DATE CRE_DT,CONTRACT_ACTIVITY_REASON.CREATION_USER_NAME CRE_USER_NM,CONTRACT_ACTIVITY_REASON.CONTRACT_ACTIVITY_REASON_IDENTIFIER CTR_ACTV_RSN_ID,CONTRACT_ACTIVITY_REASON.CONTRACT_ACTIVITY_REASON_TYPE_CODE CTR_ACTV_RSN_TYPE_CD,CONTRACT_ACTIVITY_REASON_TYPE.CONTRACT_ACTIVITY_REASON_TYPE_DESCRIPTION CTR_ACTV_RSN_TYPE_DESC,CONTRACT_ACTIVITY_REASON_TYPE.CONTRACT_ACTIVITY_TYPE_CODE CTR_ACTV_TYPE_CD,CONTRACT_ACTIVITY_REASON.CONTRACT_DETAIL_IDENTIFIER CTR_DET_ID,MASTER_CONTRACT.CONTRACT_NUMBER CTR_NBR,CONTRACT_DETAIL.CONTRACT_SUFFIX_NUMBER CTR_SFX_NBR,CONTRACT_ACTIVITY_REASON.DATA_STATUS_CODE DATA_STAT_CD,CONTRACT_ACTIVITY_REASON.LAST_CHANGE_DATE LAST_CHG_DT,CONTRACT_ACTIVITY_REASON.LAST_CHANGE_USER_NAME LAST_CHG_USER_NM,SIGNUP.SIGNUP_NUMBER SGNP_NBR,SIGNUP.SIGNUP_SUBTYPE_AGREEMENT_NAME SGNP_STYPE_AGR_NM,SIGNUP_SUB_CATEGORY.SIGNUP_SUB_CATEGORY_NAME SGNP_SUB_CAT_NM,SIGNUP_TYPE.SIGNUP_TYPE_NAME SGNP_TYPE_NM,--__CDC_OPERATION,MASTER_CONTRACT.op, 4 AS TBL_PRIORITYFrom  "fsa-{env}-ccms-cdc".MASTER_CONTRACT Left Join "fsa-{env}-ccms-cdc".CONTRACT_DETAIL  On MASTER_CONTRACT.CONTRACT_IDENTIFIER = CONTRACT_DETAIL.CONTRACT_IDENTIFIER   join "fsa-{env}-ccms-cdc".CONTRACT_ACTIVITY_REASON  on CONTRACT_ACTIVITY_REASON.CONTRACT_DETAIL_IDENTIFIER = CONTRACT_DETAIL.CONTRACT_DETAIL_IDENTIFIER   Left Join "fsa-{env}-ccms-cdc".CONTRACT_ACTIVITY_REASON_TYPE  on CONTRACT_ACTIVITY_REASON.CONTRACT_ACTIVITY_REASON_TYPE_CODE = CONTRACT_ACTIVITY_REASON_TYPE.CONTRACT_ACTIVITY_REASON_TYPE_CODE Left Join "fsa-{env}-ccms-cdc".SIGNUP on SIGNUP.SIGNUP_IDENTIFIER=MASTER_CONTRACT.SIGNUP_IDENTIFIER Left Join "fsa-{env}-ccms-cdc".SIGNUP_SUB_CATEGORY  ON SIGNUP_SUB_CATEGORY.SIGNUP_SUB_CATEGORY_CODE = SIGNUP.SIGNUP_SUB_CATEGORY_CODE Left join "fsa-{env}-ccms-cdc".SIGNUP_TYPE  On SIGNUP.SIGNUP_TYPE_CODE = SIGNUP_TYPE.SIGNUP_TYPE_CODE --WHERE __CDC_OPERATION <> 'D'WHERE MASTER_CONTRACT.op <> 'D'
UNIONSELECT MASTER_CONTRACT.ADMINISTRATIVE_COUNTY_FSA_CODE ADM_CNTY_FSA_CD,MASTER_CONTRACT.ADMINISTRATIVE_STATE_FSA_CODE ADM_ST_FSA_CD,CONTRACT_ACTIVITY_REASON.CREATION_DATE CRE_DT,CONTRACT_ACTIVITY_REASON.CREATION_USER_NAME CRE_USER_NM,CONTRACT_ACTIVITY_REASON.CONTRACT_ACTIVITY_REASON_IDENTIFIER CTR_ACTV_RSN_ID,CONTRACT_ACTIVITY_REASON.CONTRACT_ACTIVITY_REASON_TYPE_CODE CTR_ACTV_RSN_TYPE_CD,CONTRACT_ACTIVITY_REASON_TYPE.CONTRACT_ACTIVITY_REASON_TYPE_DESCRIPTION CTR_ACTV_RSN_TYPE_DESC,CONTRACT_ACTIVITY_REASON_TYPE.CONTRACT_ACTIVITY_TYPE_CODE CTR_ACTV_TYPE_CD,CONTRACT_ACTIVITY_REASON.CONTRACT_DETAIL_IDENTIFIER CTR_DET_ID,MASTER_CONTRACT.CONTRACT_NUMBER CTR_NBR,CONTRACT_DETAIL.CONTRACT_SUFFIX_NUMBER CTR_SFX_NBR,CONTRACT_ACTIVITY_REASON.DATA_STATUS_CODE DATA_STAT_CD,CONTRACT_ACTIVITY_REASON.LAST_CHANGE_DATE LAST_CHG_DT,CONTRACT_ACTIVITY_REASON.LAST_CHANGE_USER_NAME LAST_CHG_USER_NM,SIGNUP.SIGNUP_NUMBER SGNP_NBR,SIGNUP.SIGNUP_SUBTYPE_AGREEMENT_NAME SGNP_STYPE_AGR_NM,SIGNUP_SUB_CATEGORY.SIGNUP_SUB_CATEGORY_NAME SGNP_SUB_CAT_NM,SIGNUP_TYPE.SIGNUP_TYPE_NAME SGNP_TYPE_NM,--__CDC_OPERATION,SIGNUP.op,5 AS TBL_PRIORITYFrom   "fsa-{env}-ccms-cdc".SIGNUP Left Join "fsa-{env}-ccms-cdc".MASTER_CONTRACT   on SIGNUP.SIGNUP_IDENTIFIER=MASTER_CONTRACT.SIGNUP_IDENTIFIER Left Join "fsa-{env}-ccms-cdc".CONTRACT_DETAIL  On MASTER_CONTRACT.CONTRACT_IDENTIFIER = CONTRACT_DETAIL.CONTRACT_IDENTIFIER  join "fsa-{env}-ccms-cdc".CONTRACT_ACTIVITY_REASON  on CONTRACT_ACTIVITY_REASON.CONTRACT_DETAIL_IDENTIFIER = CONTRACT_DETAIL.CONTRACT_DETAIL_IDENTIFIER Left Join "fsa-{env}-ccms-cdc".CONTRACT_ACTIVITY_REASON_TYPE  on CONTRACT_ACTIVITY_REASON.CONTRACT_ACTIVITY_REASON_TYPE_CODE = CONTRACT_ACTIVITY_REASON_TYPE.CONTRACT_ACTIVITY_REASON_TYPE_CODE Left Join "fsa-{env}-ccms-cdc".SIGNUP_SUB_CATEGORY  ON SIGNUP_SUB_CATEGORY.SIGNUP_SUB_CATEGORY_CODE = SIGNUP.SIGNUP_SUB_CATEGORY_CODE  Left join "fsa-{env}-ccms-cdc".SIGNUP_TYPE  On SIGNUP.SIGNUP_TYPE_CODE = SIGNUP_TYPE.SIGNUP_TYPE_CODE --WHERE __CDC_OPERATION <> 'D'WHERE SIGNUP.op <> 'D'
UNIONSELECT MASTER_CONTRACT.ADMINISTRATIVE_COUNTY_FSA_CODE ADM_CNTY_FSA_CD,MASTER_CONTRACT.ADMINISTRATIVE_STATE_FSA_CODE ADM_ST_FSA_CD,CONTRACT_ACTIVITY_REASON.CREATION_DATE CRE_DT,CONTRACT_ACTIVITY_REASON.CREATION_USER_NAME CRE_USER_NM,CONTRACT_ACTIVITY_REASON.CONTRACT_ACTIVITY_REASON_IDENTIFIER CTR_ACTV_RSN_ID,CONTRACT_ACTIVITY_REASON.CONTRACT_ACTIVITY_REASON_TYPE_CODE CTR_ACTV_RSN_TYPE_CD,CONTRACT_ACTIVITY_REASON_TYPE.CONTRACT_ACTIVITY_REASON_TYPE_DESCRIPTION CTR_ACTV_RSN_TYPE_DESC,CONTRACT_ACTIVITY_REASON_TYPE.CONTRACT_ACTIVITY_TYPE_CODE CTR_ACTV_TYPE_CD,CONTRACT_ACTIVITY_REASON.CONTRACT_DETAIL_IDENTIFIER CTR_DET_ID,MASTER_CONTRACT.CONTRACT_NUMBER CTR_NBR,CONTRACT_DETAIL.CONTRACT_SUFFIX_NUMBER CTR_SFX_NBR,CONTRACT_ACTIVITY_REASON.DATA_STATUS_CODE DATA_STAT_CD,CONTRACT_ACTIVITY_REASON.LAST_CHANGE_DATE LAST_CHG_DT,CONTRACT_ACTIVITY_REASON.LAST_CHANGE_USER_NAME LAST_CHG_USER_NM,SIGNUP.SIGNUP_NUMBER SGNP_NBR,SIGNUP.SIGNUP_SUBTYPE_AGREEMENT_NAME SGNP_STYPE_AGR_NM,SIGNUP_SUB_CATEGORY.SIGNUP_SUB_CATEGORY_NAME SGNP_SUB_CAT_NM,SIGNUP_TYPE.SIGNUP_TYPE_NAME SGNP_TYPE_NM,--__CDC_OPERATION,SIGNUP_SUB_CATEGORY.op,6 AS TBL_PRIORITYFrom   "fsa-{env}-ccms-cdc".SIGNUP_SUB_CATEGORYLeft Join "fsa-{env}-ccms-cdc".SIGNUP ON SIGNUP_SUB_CATEGORY.SIGNUP_SUB_CATEGORY_CODE = SIGNUP.SIGNUP_SUB_CATEGORY_CODE Left Join "fsa-{env}-ccms-cdc".MASTER_CONTRACT  on SIGNUP.SIGNUP_IDENTIFIER=MASTER_CONTRACT.SIGNUP_IDENTIFIER Left Join "fsa-{env}-ccms-cdc".CONTRACT_DETAIL  On MASTER_CONTRACT.CONTRACT_IDENTIFIER = CONTRACT_DETAIL.CONTRACT_IDENTIFIER  join "fsa-{env}-ccms-cdc".CONTRACT_ACTIVITY_REASON  on CONTRACT_ACTIVITY_REASON.CONTRACT_DETAIL_IDENTIFIER = CONTRACT_DETAIL.CONTRACT_DETAIL_IDENTIFIER  Left Join "fsa-{env}-ccms-cdc".CONTRACT_ACTIVITY_REASON_TYPE  on CONTRACT_ACTIVITY_REASON.CONTRACT_ACTIVITY_REASON_TYPE_CODE = CONTRACT_ACTIVITY_REASON_TYPE.CONTRACT_ACTIVITY_REASON_TYPE_CODE Left join "fsa-{env}-ccms-cdc".SIGNUP_TYPE  On SIGNUP.SIGNUP_TYPE_CODE = SIGNUP_TYPE.SIGNUP_TYPE_CODE  --WHERE __CDC_OPERATION <> 'D'WHERE SIGNUP_SUB_CATEGORY.op <> 'D'
UNIONSELECT MASTER_CONTRACT.ADMINISTRATIVE_COUNTY_FSA_CODE ADM_CNTY_FSA_CD,MASTER_CONTRACT.ADMINISTRATIVE_STATE_FSA_CODE ADM_ST_FSA_CD,CONTRACT_ACTIVITY_REASON.CREATION_DATE CRE_DT,CONTRACT_ACTIVITY_REASON.CREATION_USER_NAME CRE_USER_NM,CONTRACT_ACTIVITY_REASON.CONTRACT_ACTIVITY_REASON_IDENTIFIER CTR_ACTV_RSN_ID,CONTRACT_ACTIVITY_REASON.CONTRACT_ACTIVITY_REASON_TYPE_CODE CTR_ACTV_RSN_TYPE_CD,CONTRACT_ACTIVITY_REASON_TYPE.CONTRACT_ACTIVITY_REASON_TYPE_DESCRIPTION CTR_ACTV_RSN_TYPE_DESC,CONTRACT_ACTIVITY_REASON_TYPE.CONTRACT_ACTIVITY_TYPE_CODE CTR_ACTV_TYPE_CD,CONTRACT_ACTIVITY_REASON.CONTRACT_DETAIL_IDENTIFIER CTR_DET_ID,MASTER_CONTRACT.CONTRACT_NUMBER CTR_NBR,CONTRACT_DETAIL.CONTRACT_SUFFIX_NUMBER CTR_SFX_NBR,CONTRACT_ACTIVITY_REASON.DATA_STATUS_CODE DATA_STAT_CD,CONTRACT_ACTIVITY_REASON.LAST_CHANGE_DATE LAST_CHG_DT,CONTRACT_ACTIVITY_REASON.LAST_CHANGE_USER_NAME LAST_CHG_USER_NM,SIGNUP.SIGNUP_NUMBER SGNP_NBR,SIGNUP.SIGNUP_SUBTYPE_AGREEMENT_NAME SGNP_STYPE_AGR_NM,SIGNUP_SUB_CATEGORY.SIGNUP_SUB_CATEGORY_NAME SGNP_SUB_CAT_NM,SIGNUP_TYPE.SIGNUP_TYPE_NAME SGNP_TYPE_NM,--__CDC_OPERATION,SIGNUP_TYPE.op,7 AS TBL_PRIORITYFrom   "fsa-{env}-ccms-cdc".SIGNUP_TYPELeft Join "fsa-{env}-ccms-cdc".SIGNUP On SIGNUP.SIGNUP_TYPE_CODE = SIGNUP_TYPE.SIGNUP_TYPE_CODE Left join "fsa-{env}-ccms-cdc".SIGNUP_SUB_CATEGORY  ON SIGNUP_SUB_CATEGORY.SIGNUP_SUB_CATEGORY_CODE = SIGNUP.SIGNUP_SUB_CATEGORY_CODE  Left Join "fsa-{env}-ccms-cdc".MASTER_CONTRACT  on SIGNUP.SIGNUP_IDENTIFIER=MASTER_CONTRACT.SIGNUP_IDENTIFIER  Left Join "fsa-{env}-ccms-cdc".CONTRACT_DETAIL   On MASTER_CONTRACT.CONTRACT_IDENTIFIER = CONTRACT_DETAIL.CONTRACT_IDENTIFIER   join "fsa-{env}-ccms-cdc".CONTRACT_ACTIVITY_REASON  on CONTRACT_ACTIVITY_REASON.CONTRACT_DETAIL_IDENTIFIER = CONTRACT_DETAIL.CONTRACT_DETAIL_IDENTIFIER  Left Join "fsa-{env}-ccms-cdc".CONTRACT_ACTIVITY_REASON_TYPE  on CONTRACT_ACTIVITY_REASON.CONTRACT_ACTIVITY_REASON_TYPE_CODE = CONTRACT_ACTIVITY_REASON_TYPE.CONTRACT_ACTIVITY_REASON_TYPE_CODE --WHERE __CDC_OPERATION <> 'D'WHERE SIGNUP_TYPE.op <> 'D') STG_ALL) STG_UNQWHERE row_num_part = 1AND CONTRACT_ACTIVITY_REASON.dart_filedate BETWEEN DATE '{ETL_START_DATE}' AND DATE '{ETL_END_DATE}'
)
UNIONSELECT DISTINCTNULL ADM_CNTY_FSA_CD,NULL ADM_ST_FSA_CD,CONTRACT_ACTIVITY_REASON.CREATION_DATE CRE_DT,CONTRACT_ACTIVITY_REASON.CREATION_USER_NAME CRE_USER_NM,CONTRACT_ACTIVITY_REASON.CONTRACT_ACTIVITY_REASON_IDENTIFIER CTR_ACTV_RSN_ID,CONTRACT_ACTIVITY_REASON.CONTRACT_ACTIVITY_REASON_TYPE_CODE CTR_ACTV_RSN_TYPE_CD,NULL CTR_ACTV_RSN_TYPE_DESC,NULL CTR_ACTV_TYPE_CD,CONTRACT_ACTIVITY_REASON.CONTRACT_DETAIL_IDENTIFIER CTR_DET_ID,NULL CTR_NBR,NULL CTR_SFX_NBR,CONTRACT_ACTIVITY_REASON.DATA_STATUS_CODE DATA_STAT_CD,CONTRACT_ACTIVITY_REASON.LAST_CHANGE_DATE LAST_CHG_DT,CONTRACT_ACTIVITY_REASON.LAST_CHANGE_USER_NAME LAST_CHG_USER_NM,NULL SGNP_NBR,NULL SGNP_STYPE_AGR_NM,NULL SGNP_SUB_CAT_NM,NULL SGNP_TYPE_NM,'D' CDC_OPER_CD,1 AS row_num_partFROM "fsa-{env}-ccms-cdc".CONTRACT_ACTIVITY_REASON--WHERE __CDC_OPERATION = 'D'
WHERE CONTRACT_ACTIVITY_REASON.op = 'D'